import type { FunctionComponent, ReactNode } from 'react';
import type { SemanticMode, Theme } from './meli-themes/types/theme';

export type ThemeCustomVariantProp = {
  customVariant?: string;
};

type NativeStylesDeclaration = {
  [K in keyof CSSStyleDeclaration]?: CSSStyleDeclaration[K];
};

type StylesDeclarationObject = NativeStylesDeclaration & {
  [key: string]: NativeStylesDeclaration | StylesDeclarationObject;
};

export type CustomVariant = {
  id: string;
  propsMatcher: Record<string, unknown> | ((props: unknown) => boolean);
  styles: StylesDeclarationObject;
};

export type RegisterComponentsClassesObject = {
  className: string;
  variants: Array<CustomVariant>;
};

export type GetComponentsStyles =
  | Map<string, RegisterComponentsClassesObject>
  | ReadonlyMap<string, RegisterComponentsClassesObject>;

type TypeKeysWithAndesExtraAttributes<T> = {
  [K in keyof T]?: T[K] & {
    [key: string]: unknown;
    styleOverrides?: StylesDeclarationObject;
    variants?: Array<CustomVariant>;
  };
};

export type AndesBaseTheme = {
  colorSchemes?: Theme['semantic'];
  components?: Theme['components'];
  core?: Theme['core'];
};

export type ThemeVariables = {
  core?: Theme['core'];
  semantic?: SemanticMode;
};

type AndesTheme = AndesBaseTheme & {
  components?: TypeKeysWithAndesExtraAttributes<Theme['components']>;
};

export type AndesProviderTheme = AndesTheme & Record<string, unknown>;

type AndesThemeProviderSpecificProps = {
  /**
   * Base theme to be used by the provider.
   * The theme that you provide will be merged with the this base theme.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/themes#andesthemeprovider-api | Documentation}
   * @default 'ML'
   */
  baseTheme?: 'ML' | 'MP';

  /**
   * Children to be wrapped with the provider.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/themes#andesthemeprovider-api | Documentation}
   */
  children: ReactNode;

  /**
   * Id to be used as an identifier internally in the context to identify your theme.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/themes#andesthemeprovider-api | Documentation}
   */
  id?: string;

  /**
   * Flag to override the parent theme in the context.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/themes#andesthemeprovider-api | Documentation}
   * @default false
   */
  override?: boolean;

  /**
   * Styles options object to be used when building the theme styles.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/themes#andesthemeprovider-api | Documentation}
   */
  stylesOptions?: StylesOptions;

  /**
   * Theme object to be used by the context.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/themes#andesthemeprovider-api | Documentation}
   * @default {}
   */
  theme?: AndesProviderTheme;
};

export const AndesThemeProvider: FunctionComponent<AndesThemeProviderSpecificProps>;

export type StylesOptions = {
  /**
   * Indicates if the styles should be created on SSR or CSR.
   *
   * @default 'SSR'
   */
  buildOn: 'CSR' | 'SSR';

  /**
   * Determines whether styles should be injected externally using the `getThemeStyles` function.
   * If set to false, styles will be injected internally by the theme provider.
   *
   * @default false
   */
  externalInject?: boolean;

  /**
   * Indicates if the styles should be created at the body selector.
   *
   * @default false
   */
  global?: boolean;
};

export type ThemeHash = { 'data-t-hash': string };
export type ThemeContextValue = {
  getThemedComponentClasses: (component: string, props?: object) => string;
  getThemeStyles: (options?: StylesOptions) => string;
  theme: CreateTheme['theme'];
  themeHash: CreateTheme['themeHash'];
  themeVariables: CreateTheme['themeVariables'];
};

export const useThemeContext: () => ThemeContextValue;

export type CreateTheme = {
  componentsClasses: GetComponentsStyles;
  getComponentVariants: (
    component: string,
    props: object,
  ) => Array<CustomVariant>;
  getStyles: (components?: GetComponentsStyles, global?: boolean) => string;
  theme: AndesProviderTheme;
  themeHash: ThemeHash;
  themeVariables: ThemeVariables;
};

export const useCreateTheme: (
  theme: AndesProviderTheme,
  baseTheme: 'ML' | 'MP',
  id: string,
  override?: boolean,
) => CreateTheme;
